-- Migration to add domain field to Tenant table and set up initial data\n\n-- Add domain column if it doesn't exist\nALTER TABLE \"Tenant\" ADD COLUMN IF NOT EXISTS \"domain\" TEXT;\n\n-- Add unique constraint on domain\nALTER TABLE \"Tenant\" ADD CONSTRAINT \"Tenant_domain_key\" UNIQUE (\"domain\");\n\n-- Insert sample tenant data (adjust as needed)\nINSERT INTO \"Tenant\" (\n  \"email\", \n  \"name\", \n  \"password\", \n  \"domain\", \n  \"dbName\", \n  \"dbUser\", \n  \"dbPassword\",\n  \"isActive\"\n) VALUES \n(\n  'clienta@example.com',\n  'Client A',\n  '$2b$10$hashedpassword1', -- Replace with actual hashed password\n  'crm.luisant.in',\n  'tenant_clienta',\n  'postgres',\n  'root',\n  true\n),\n(\n  'clientb@example.com',\n  'Client B', \n  '$2b$10$hashedpassword2', -- Replace with actual hashed password\n  'clientb.example.com', -- Replace with actual domain\n  'tenant_clientb',\n  'postgres', \n  'root',\n  true\n)\nON CONFLICT (\"email\") DO NOTHING;\n\n-- Update existing tenants with domains if needed\n-- UPDATE \"Tenant\" SET \"domain\" = 'crm.luisant.in' WHERE \"id\" = 1;\n-- UPDATE \"Tenant\" SET \"domain\" = 'other-domain.com' WHERE \"id\" = 2;